import React from "react"

class Evalulation extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            results: []
        };
    }

        componentDidMount() {


            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            //headers.append('Access-Control-Allow-Origin', 'http://localhost:3000');
            //headers.append('Access-Control-Allow-Credentials', 'true');

            fetch(`http://localhost:9000/amioncall`, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({results: response})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)
              })
              .catch(err => {
                console.log(err);
              });


          }

          render() {


            var todayDate = ""
            var teamHtml = ""

            var content = []
                for (var x in this.state.results) {

                      console.log(this.state.results[x])
                      todayDate = this.state.results[x].date
                      teamHtml = <div style={{marginBottom: '10px'}}><b>{this.state.results[x].team }: <u>{this.state.results[x].name}</u></b></div>


                      var residentsContent = []
                      for (var y in this.state.results[x].residents) {
                        residentsContent.push(<div style={{marginLeft: '10px'}}>- {this.state.results[x].residents[y].assignment}: {this.state.results[x].residents[y].name}</div>)
                      }

                    content.push(<div>************************************************</div>)

                    content.push(teamHtml)
                    content.push(residentsContent)
                    content.push(<div>&nbsp;</div>)

                }

            return (
                <div className="container">
                  <div className="row justify-content-center">
                    <div className="col-md-8">
                      <h1 className="display-4 text-center">Date: {todayDate}</h1>


{content}


<div>POST <b>evals/initiate</b></div>
<div>https://medhub.com/functions/api/evals/initiate</div>
<div>Delivers a new evaluation.</div>

Input Variables
View More
Variable Name	Data Type	Required	Version	Notes
evaluationID	integer	Yes	v1.15	Use evals/forms to get a list of all active evaluations for a given program or course.
evaluation_type	integer	Yes	v1.15	Use evals/types to get a list of all available evaluation types.
evaluator_userID	integer	Yes	v1.15	Identifies the user that will recieve the evaluation.
programID	integer	Yes*	v1.15	Identifies the program delivering the evaluation. *Required if courseID not provided.
courseID	integer	Yes*	v1.15	Identifies the course delivering the evaluation. *Required if programID not provided.
evaluatee_userID	integer	Yes*	v1.15	*Required for all evaluation types where the target is a person.
procedureID	integer	No*	v1.15	*Required for all evaluations of procedures.
lectureID	integer	No*	v1.15	*Required for all evaluations of conferences or sessions
globalserviceID	integer	No*	v1.15	*Required if evaluation is of a service AND clinicnameID is not provided. Use schedules/services to get a list of service groups for a given program.
clinicnameID	integer	No*	v1.15	*Required if evaluation is of a service AND globalserviceID is not provided. Use schedules/clinics to get a list of clinics defined for a given program or course.
notify	boolean	No	v1.15	Pass TRUE to deliver an email notification to the evaluator.
Response Data
Field Name	Description	Data Type	Version	Notes
responseID	unique identifier for evaluation response	integer	v1.15	Value "0" indicates a failed delivery.

                    </div>
                  </div>
                </div>
            );
          }


  };

  export default Evalulation
